import numpy as npimport pandas as pdimport jsonfrom petitRADTRANS.radtrans import Radtransfrom criresviz.common import OPACITYfrom criresviz.models.feature import find_active_regionsfrom config import (    MOLECULES,    OUTPUT,    TEMPERATURE,    PRESSURE,    WAVELENGTH_MIN,    WAVELENGTH_MAX,    TARGET_P,    TARGET_T,    c)SHOW = False # to plot the opacity once the baseline is removeddef compute_opacity(species):    """    Compute the opacity spectrum of one molecule.    Parameters    ----------    species : str    Returns    -------    pandas.DataFrame    """    atmosphere = Radtrans(    pressures=PRESSURE,    line_species=[species],    wavelength_boundaries=np.array([WAVELENGTH_MIN, WAVELENGTH_MAX]),    line_opacity_mode="lbl",    )        pt_grid = (        atmosphere.lines_loaded_opacities        ["temperature_pressure_grid"][species]    )        distance = (        (pt_grid[:,0] - TARGET_T)**2        +        (np.log10(pt_grid[:,1]) - np.log10(TARGET_P))**2    )        index = np.argmin(distance)        opacity_grid = (atmosphere.lines_loaded_opacities["opacity_grid"][species])    opacity = opacity_grid[0, :, index]        wavelength_um = (c / atmosphere.frequencies) * 1e4    kernel = int(40 / np.median(np.diff(wavelength_um)))    baseline = pd.Series(opacity).rolling(kernel | 1, center=True, min_periods=1).median().to_numpy()    opacity = opacity - baseline        regions = find_active_regions(        wavelength_um,        opacity,        show=SHOW,    )        return regions           def save(regions, species):    metadata = {        "version": 1,        "species": species,        "temperature": TARGET_T,        "pressure": TARGET_P,        "pressure_unit": "Pa",        "wavelenght_range": [WAVELENGTH_MIN, WAVELENGTH_MAX],        "wavelength_unit": "micron",        "opacity_mode": "lbl",        "threshold": 0.6,        "source": "petitRADTRANS",        "active_regions": regions,            }    with open(OPACITY / f"{species}.json", "w") as f:        json.dump(            metadata,            f,            indent=4,        )    print(f"Saved {species}.json")def main():    for species in MOLECULES:            print(f"Computing {species}")            regions = compute_opacity(species)            save(            regions,            species,        )if __name__ == "__main__":    main()